import android.content.Context
import android.content.SharedPreferences
import android.util.Base64
import java.security.MessageDigest
import java.util.*

class AuthManager private constructor(context: Context) {
    private val prefs: SharedPreferences = context.getSharedPreferences("auth", Context.MODE_PRIVATE)
    private val editor: SharedPreferences.Editor = prefs.edit()

    fun saveAuthToken(token: String, userId: String) {
        val encodedToken = Base64.encodeToString(token.toByteArray(), Base64.NO_WRAP)
        editor.putString("token", encodedToken)
        editor.putString("user_id", userId)
        editor.apply()
    }

    fun getAuthToken(): String? {
        return prefs.getString("token", null)?.let { Base64.decode(it, Base64.NO_WRAP).toString(Charsets.UTF_8) }
    }

    fun getUserID(): String? {
        return prefs.getString("user_id", null)
    }

    fun isUserLoggedIn(): Boolean {
        val token = getAuthToken()
        return token != null && token.isNotEmpty() && getUserID() != null
    }

    companion object {
        @Volatile
        private var instance: AuthManager? = null

        fun getInstance(context: Context): AuthManager {
            if (instance == null) {
                synchronized(this) {
                    if (instance == null) {
                        instance = AuthManager(context)
                    }
                }
            }
            return instance!!
        }
    }
}

class SecureAuthManager(private val context: Context) : AuthManager(context) {

    fun saveAuthTokenSecurely(token: String, userId: String) {
        val hashedToken = MessageDigest.getInstance("SHA-256").digest(token.toByteArray()).toHex()
        saveAuthToken(hashedToken, userId)
    }

    private fun ByteArray.toHex(): String {
        return joinToString(separator = "") { "%02x".format(it) }
    }
}

fun Context.getAuthManager(): AuthManager {
    return AuthManager.getInstance(this)
}